function splitUniqueEmojis(raw: string): string[] {
  return Array.from(new Set(raw.trim().split(/\s+/u).filter(Boolean)));
}

function sliceEmojiRange(emojis: string[], start: string, end: string): string[] {
  const startIndex = emojis.indexOf(start);
  const endIndex = emojis.indexOf(end);

  if (startIndex === -1 || endIndex === -1 || startIndex > endIndex) {
    throw new Error(`Invalid emoji range: ${start} -> ${end}`);
  }

  return emojis.slice(startIndex, endIndex + 1);
}

